# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = {}

class GameServer:
    def __init__(self):
        self.players = {}
        self.locks = defaultdict(asyncio.Lock)

    async def handle_client(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            action = data.get("action")
            
            if action == "add_player":
                player_id = data.get("player_id")
                if player_id not in self.players:
                    self.players[player_id] = Player(player_id)
                    await websocket.send(json.dumps({"status": "success", "message": f"Player {player_id} added."}))
                else:
                    await websocket.send(json.dumps({"status": "error", "message": f"Player {player_id} already exists."}))

            elif action == "add_item":
                player_id = data.get("player_id")
                item_id = data.get("item_id")
                quantity = data.get("quantity", 1)
                if player_id in self.players:
                    async with self.locks[player_id]:
                        if item_id not in self.players[player_id].inventory:
                            self.players[player_id].inventory[item_id] = 0
                        self.players[player_id].inventory[item_id] += quantity
                        await websocket.send(json.dumps({"status": "success", "message": f"Added {quantity} of {item_id} to {player_id}'s inventory."}))
                else:
                    await websocket.send(json.dumps({"status": "error", "message": f"Player {player_id} does not exist."}))

            elif action == "trade_items":
                sender_id = data.get("sender_id")
                receiver_id = data.get("receiver_id")
                item_id = data.get("item_id")
                quantity = data.get("quantity", 1)
                
                if sender_id in self.players and receiver_id in self.players:
                    async with self.locks[sender_id], self.locks[receiver_id]:
                        if item_id in self.players[sender_id].inventory and self.players[sender_id].inventory[item_id] >= quantity:
                            self.players[sender_id].inventory[item_id] -= quantity
                            if item_id not in self.players[receiver_id].inventory:
                                self.players[receiver_id].inventory[item_id] = 0
                            self.players[receiver_id].inventory[item_id] += quantity
                            await websocket.send(json.dumps({"status": "success", "message": f"Traded {quantity} of {item_id} from {sender_id} to {receiver_id}."}))
                        else:
                            await websocket.send(json.dumps({"status": "error", "message": f"Not enough {item_id} in sender's inventory."}))
                else:
                    await websocket.send(json.dumps({"status": "error", "message": "Invalid player IDs."}))

            elif action == "get_inventory":
                player_id = data.get("player_id")
                if player_id in self.players:
                    await websocket.send(json.dumps({"status": "success", "inventory": self.players[player_id].inventory}))
                else:
                    await websocket.send(json.dumps({"status": "error", "message": f"Player {player_id} does not exist."}))

            else:
                await websocket.send(json.dumps({"status": "error", "message": "Invalid action"}))

    async def start_server(self):
        async with websockets.serve(self.handle_client, "localhost", 8765):
            await asyncio.Future()  # Run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())